app = Flask(__name__)

# --- Metrics Definitions ---
# Track request counts by method, endpoint, and status code (safe dimensions)
REQUEST_COUNT = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "status_code"],
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=[0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0],
)

REQUEST_SIZE = Histogram(
    "http_request_size_bytes",
    "HTTP request body size in bytes",
    ["method", "endpoint"],
    buckets=[0, 100, 500, 1000, 5000, 10000, 50000, 100000],
)

RESPONSE_SIZE = Histogram(
    "http_response_size_bytes",
    "HTTP response body size in bytes",
    ["method", "endpoint"],
    buckets=[0, 100, 500, 1000, 5000, 10000, 50000, 100000],
)

ACTIVE_REQUESTS = Gauge(
    "http_active_requests",
    "Number of active HTTP requests",
    ["method", "endpoint"],
)

# Track unique users without exposing their IDs
# Use a counter per anonymized user tier/role instead
REQUEST_BY_AUTH_TYPE = Counter(
    "http_requests_by_auth_type_total",
    "Requests by authentication type",
    ["auth_type"],  # e.g., "api_key", "bearer_token", "none"
)

ERROR_COUNT = Counter(
    "http_errors_total",
    "Total HTTP errors",
    ["method", "endpoint", "error_type"],
)


def _get_safe_endpoint():
    """Return a safe, low-cardinality endpoint label."""
    if request.url_rule:
        return request.url_rule.rule
    return "unknown"


def _get_auth_type():
    """Determine auth type without exposing credentials."""
    if request.headers.get("Authorization", "").startswith("Bearer "):
        return "bearer_token"
    elif request.headers.get("X-API-Key"):
        return "api_key"
    elif request.headers.get("Authorization", "").startswith("Basic "):
        return "basic_auth"
    return "none"


@app.before_request
def before_request_metrics():
    """Record metrics before processing request."""
    g.start_time = time.time()
    endpoint = _get_safe_endpoint()

    # Skip metrics endpoint itself to avoid recursion
